$ErrorActionPreference = 'SilentlyContinue'
Write-Output "=== Get-Command ==="
$git = Get-Command git -ErrorAction SilentlyContinue
$gh  = Get-Command gh  -ErrorAction SilentlyContinue
if ($git) { Write-Output ("git: " + $git.Source) } else { Write-Output "git: NOT IN PATH" }
if ($gh)  { Write-Output ("gh:  " + $gh.Source)  } else { Write-Output "gh:  NOT IN PATH" }

Write-Output "=== Registry uninstall scan ==="
$keys = 'HKLM:\SOFTWARE\Microsoft\Windows\CurrentVersion\Uninstall\*','HKLM:\SOFTWARE\WOW6432Node\Microsoft\Windows\CurrentVersion\Uninstall\*','HKCU:\SOFTWARE\Microsoft\Windows\CurrentVersion\Uninstall\*'
Get-ItemProperty $keys | Where-Object { $_.DisplayName -match 'git|github' } | Select-Object DisplayName, InstallLocation, DisplayVersion | Format-Table -AutoSize

Write-Output "=== App Paths registry ==="
$appPaths = 'HKLM:\SOFTWARE\Microsoft\Windows\CurrentVersion\App Paths\git.exe','HKLM:\SOFTWARE\Microsoft\Windows\CurrentVersion\App Paths\gh.exe','HKCU:\SOFTWARE\Microsoft\Windows\CurrentVersion\App Paths\git.exe','HKCU:\SOFTWARE\Microsoft\Windows\CurrentVersion\App Paths\gh.exe'
foreach ($p in $appPaths) {
  $v = (Get-ItemProperty $p).'(default)'
  if ($v) { Write-Output ($p + " -> " + $v) }
}

Write-Output "=== Drive scan (top dirs) ==="
foreach ($d in 'C:\','D:\','E:\','F:\') {
  if (Test-Path $d) {
    Get-ChildItem $d -Filter 'git.exe' -Recurse -Depth 4 -ErrorAction SilentlyContinue |
      Select-Object -First 5 -ExpandProperty FullName
  }
}
Write-Output "=== done ==="

