$src = 'C:\Users\lmhl\.claude\projects\E--CCproject'
$dst = 'E:\CCproject\claude-history'
if (-not (Test-Path $dst)) { New-Item -ItemType Directory -Path $dst | Out-Null }

$files = @(
  '1198ccd0-f101-4ff2-99b3-876272c47592.jsonl',
  '541e9075-cf30-41ef-80f2-6a7064890203.jsonl'
)

foreach ($f in $files) {
  $s = Join-Path $src $f
  $d = Join-Path $dst $f
  if (Test-Path $s) {
    Copy-Item -LiteralPath $s -Destination $d -Force
    $size = (Get-Item $d).Length
    Write-Output ("OK: " + $f + " (" + [math]::Round($size/1KB, 1) + " KB)")
  } else {
    Write-Output ("MISS: " + $f)
  }
}
Write-Output "--- final listing ---"
Get-ChildItem $dst | Select-Object Name, @{N='KB';E={[math]::Round($_.Length/1KB,1)}} | Format-Table -AutoSize

